esqlQuery.esql:
FROM metrics-kafkametricsreceiver.otel-*
// Partition metrics: replicas vs in-sync replicas
| WHERE kafka.partition.replicas IS NOT NULL AND kafka.partition.replicas_in_sync IS NOT NULL
| STATS replicas = MAX(kafka.partition.replicas),
    replicas_in_sync = MAX(kafka.partition.replicas_in_sync)
  BY attributes.topic, attributes.partition
// Alert when any replica is out of sync (replication degraded)
// Indicates broker failures, network issues, or overloaded followers
| WHERE replicas > replicas_in_sync
| SORT replicas_in_sync ASC
